USE `arbitrary_gate`;

-- Clear existing data
DELETE FROM `event_card`;

-- Batch 1: EV001 ~ EV050
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV001','涿鹿·黄帝崛起','先秦','涿鹿（今河北）','黄帝与炎帝在涿鹿之野展开华夏民族史上规模最大的部族战争，黄帝最终胜出，统一黄河流域各部落，开创华夏文明新纪元，奠定中华民族最初的文化认同。',80,'华夏始祖时代'),('EV002','神农尝百草','先秦','荆楚地区','神农氏亲尝百草辨别药性，日遇七十二毒，以茶解之，开创中医药学之先河，被后世尊为农业之神与医药之祖。',50,'华夏始祖时代'),('EV003','阪泉·炎黄之战','先秦','阪泉（今山西）','黄帝与炎帝两大部落在阪泉之野三度交战，黄帝最终收服炎帝部族，两族融合为华夏主体族群，中华民族由此而来。',80,'华夏始祖时代'),('EV004','蚩尤之乱','先秦','涿鹿（今河北）','九黎部落首领蚩尤率八十一部族作乱，呼风唤雨，无人能敌。黄帝与炎帝联手将其击败，开创华夏和平。',80,'华夏始祖时代'),('EV005','伏羲创八卦','先秦','陈仓（今陕西）','伏羲氏仰观天文俯察地理，悟得阴阳变化之理，创制八卦，开启中华哲学与易学之源头。',100,'上古圣王时代'),('EV006','女娲补天','先秦','不周山（传说）','共工怒触不周山，天倾地裂，洪水泛滥。女娲炼五色石补天，斩巨鳌立四极，救万民于水火，中华神话中最壮烈的救世壮举。',100,'上古神话时代'),('EV007','大禹治水','先秦','九州（黄河长江流域）','帝舜之时，洪水滔天，大禹承父遗志，劳身焦思，居外十三年，三过家门而不入，改堵为疏导洪水，终平水患。',100,'尧舜禹时代'),('EV008','禹王分九州','先秦','冀州（今河北）','大禹平定水患后，将天下划分为冀、兖、青、徐、扬、荆、豫、梁、雍九州，奠定中国行政区划雏形。',50,'夏朝初期'),('EV009','夏启继位','先秦','阳城（今河南）','大禹逝世后，伯益推让，启即天子之位，结束禅让制，建立世袭制夏朝，中国历史上第一个奴隶制王朝由此诞生。',80,'夏朝初期'),('EV010','有扈氏之乱','先秦','甘（今陕西鄠县）','夏启继位，有扈氏不服，起兵反抗。夏启率六军征讨，双方战于甘，大败有扈氏，巩固夏朝政权。',50,'夏朝初期'),('EV011','太康失国','先秦','斟鄩（今河南巩义）','夏朝第三任君主太康耽于游猎，不理朝政，被东夷族有穷氏首领后羿篡夺王位，史称"太康失国"。',50,'夏朝前期'),('EV012','少康复国','先秦','斟鄩（今河南）','太康失国后，其孙少康在有仍氏、有虞氏帮助下积蓄力量，灭有穷氏，复兴夏朝，史称"少康中兴"。',80,'夏朝前期'),('EV013','夏桀亡国','先秦','斟鄩（今河南）','夏朝末代君主桀暴虐无道，宠幸妹喜，筑酒池肉林。商族首领成汤起兵伐夏，夏朝覆灭，中国进入商朝文明。',80,'夏朝末期'),('EV014','商汤革命','先秦','亳（今河南商丘）','成汤见夏桀无道，以"时日曷丧，予及汝偕亡"为誓，率诸侯伐夏，建立商朝，定都亳，推行德政。',100,'商朝初期'),('EV015','伊尹辅政','先秦','亳（今河南商丘）','伊尹原为有莘氏媵臣，后为成汤重用，辅佐商朝五代君主，以调和五味之道喻治国之法。',100,'商朝初期'),('EV016','盘庚迁殷','先秦','殷（今河南安阳）','商王盘庚为结束贵族纷争与水患威胁，毅然将国都由奄迁至殷，推行改革，商朝国势重新振兴。',80,'商朝中期'),('EV017','武丁盛世','先秦','殷（今河南安阳）','商王武丁励精图治，重用出身卑微的傅说为相，开创"武丁中兴"，商朝疆域最广，经济文化达到鼎盛。',80,'商朝鼎盛期'),('EV018','妇好征羌','先秦','殷（今河南安阳）','商王武丁之妻妇好是中国历史上有据可查的第一位女性军事统帅，率军征讨羌方、土方等方国，立下赫赫战功。',50,'商朝鼎盛期'),('EV019','商纣亡国','先秦','朝歌（今河南淇县）','商朝末代君主纣王暴虐无道，宠幸妲己，设立炮烙之刑，最终被周武王率诸侯联军灭国，商朝覆亡。',100,'商朝末期'),('EV020','文王被囚','先秦','羑里（今河南汤阴）','周文王姬昌因受纣王猜忌被囚禁于羑里七年，在狱中推演八卦为六十四卦，作《周易》。',100,'商朝末期'),('EV021','姜尚钓鱼','先秦','渭水（今陕西宝鸡）','姜子牙怀才不遇，垂钓于渭水之滨，以直钩离水三尺，愿者上钩。文王出猎相遇，大悦，拜为军师。',100,'商周之际'),('EV022','武王伐纣','先秦','牧野（今河南新乡）','周武王在姜尚辅佐下，率兵车三百乘东进伐纣。双方战于牧野，商军倒戈，纣王自焚，商朝覆灭。',100,'商周之际'),('EV023','周公制礼','先秦','洛邑（今河南洛阳）','周公旦辅佐成王，制礼作乐，建立宗法制与分封制，奠定周朝八百年统治根基。',100,'西周初期'),('EV024','成王践位','先秦','洛邑（今河南洛阳）','周成王继位后，周公辅政，平定管蔡之乱，营建洛邑，开创"成康之治"，西周进入鼎盛时期。',50,'西周初期'),('EV025','分封天下','先秦','关中及中原','周武王灭商后大规模分封诸侯，将王族、功臣、先圣后裔分封各地，建立七十一国，拱卫周室。',80,'西周初期'),('EV026','穆王西巡','先秦','昆仑（今新疆）','周穆王喜好游牧，曾西巡至昆仑山，会见西王母，增进中原与西域的文化交流。',50,'西周中期'),('EV027','厉王止谤','先秦','镐京（今陕西西安）','周厉王暴虐，以专利为政，严禁人民谈论国事，最终引发"国人暴动"，厉王被流放于彘。',50,'西周后期'),('EV028','共和行政','先秦','镐京（今陕西西安）','厉王被逐后，召公、周公二相共同执政十四年，是中国历史有确切纪年开始的标志（公元前841年）。',80,'西周后期'),('EV029','宣王中兴','先秦','镐京（今陕西西安）','周宣王任贤臣，整顿朝政，讨伐四夷，西周国势有所恢复，史称"宣王中兴"。',50,'西周后期'),('EV030','烽火戏诸侯','先秦','骊山（今陕西西安）','周幽王宠爱褒姒，数次点燃烽火戏弄诸侯。及后犬戎入侵，诸侯不再响应，幽王被杀于骊山脚下，西周覆亡。',100,'西周末期'),('EV031','平王东迁','先秦','洛邑（今河南洛阳）','犬戎攻破镐京后，周平王在郑、秦、晋等诸侯护送下东迁洛邑，建立东周，春秋战国大时代由此开启。',80,'春秋初期'),('EV032','郑庄公克段','先秦','新郑（今河南）','郑庄公之弟共叔段在母亲姜氏支持下谋反，郑庄公先纵其骄，后命子封伐之，共叔段兵败出逃。',50,'春秋初期'),('EV033','齐桓称霸','先秦','临淄（今山东）','齐桓公小白在管仲辅佐下，以"尊王攘夷"为旗号，九合诸侯，一匡天下，成为春秋五霸之首。',100,'春秋初期'),('EV034','管仲改革','先秦','临淄（今山东）','管仲相齐，实行相地而衰征、盐铁专营、统一货币等改革，使齐国由弱转强，开创中国历史上第一次系统性变法。',100,'春秋初期'),('EV035','曹刿论战','先秦','长勺（今山东莱芜）','齐国伐鲁，曹刿于长勺之战中待齐军三鼓之后发起进攻，大败齐军，留下"一鼓作气"之千古战典。',50,'春秋初期'),('EV036','晋文称霸','先秦','绛县（今山西）','晋文公重耳流亡十九年，归国后励精图治，城濮之战大败楚军，成为春秋五霸之一。',100,'春秋中期'),('EV037','重耳流亡','先秦','列国','晋献公诸子争位，公子重耳被迫流亡列国十九年，终被秦穆公护送归晋，成就霸业。',100,'春秋中期'),('EV038','城濮之战','先秦','城濮（今山东鄄城）','晋文公与楚国争霸，两军大战于城濮。晋军退避三舍，后发制人，大败楚军，奠定晋国中原霸主地位。',80,'春秋中期'),('EV039','烛之武退秦师','先秦','汜南（今河南）','郑国老臣烛之武夜缒而出，面见秦穆公，以"亡郑陪邻"之理说服秦军撤退，孤身化解亡国危机。',100,'春秋中期'),('EV040','崤山之战','先秦','崤山（今河南）','秦晋围郑，秦军偷袭郑国途中，晋军联合姜戎在崤山设伏，全歼秦军，俘获秦军三帅。',50,'春秋中期'),('EV041','秦穆称霸西戎','先秦','雍州（今陕西）','秦穆公任用由余谋略，灭西戎十二国，开地千里，遂霸西戎，周襄王赐金鼓以示嘉奖。',50,'春秋中期'),('EV042','楚庄王问鼎','先秦','洛邑（今河南）','楚庄王率兵北伐，陈兵周郊，问九鼎之轻重，意图取代周朝。王孙满以"在德不在鼎"婉拒。',100,'春秋中期'),('EV043','邲之战','先秦','邲（今河南郑州）','楚庄王率军大败晋军于邲，晋军溃逃时争船渡河，自相残杀，楚国饮马黄河，霸业达于极盛。',80,'春秋中期'),('EV044','晏子使楚','先秦','郢都（今湖北）','齐国晏婴身材矮小，出使楚国，楚王三次侮辱晏子。晏子以"橘生淮南"之喻巧妙反击，维护了齐国尊严。',100,'春秋中期'),('EV045','孙武演兵','先秦','吴国（今江苏）','齐国军事家孙武以宫中一百八十名宫女演练阵法，宠妃轻视号令，孙武立斩二妃，宫女闻鼓肃然。',100,'春秋末期'),('EV046','伍子胥出亡','先秦','郢都（今湖北）','伍子胥之父伍奢被楚平王冤杀，伍子胥出亡吴国，"一夜白头"过昭关，后助吴王阖闾攻入郢都。',100,'春秋末期'),('EV047','吴越争霸','先秦','会稽（今浙江）','吴王夫差大败越王勾践于会稽，勾践入吴为奴三年，归国后卧薪尝胆，最终灭吴称霸。',100,'春秋末期'),('EV048','卧薪尝胆','先秦','会稽（今浙江）','越王勾践归国后，将苦胆悬于座位上方，坐卧即尝。十年生聚，十年教训，终于灭吴雪耻。',100,'春秋末期'),('EV049','三家分晋','先秦','绛县（今山西）','晋国被韩、赵、魏三家瓜分，晋静公被废，中国历史由此进入战国七雄时代。',80,'春秋末期'),('EV050','李悝变法','先秦','魏国（今河南）','魏文侯重用李悝实行变法，推行"平籴法"，编纂《法经》为中国第一部系统的成文法典。',100,'战国初期');

-- Batch 2: EV051 ~ EV100
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV051','吴起在楚','先秦','楚国','吴起自魏奔楚，辅佐楚悼王实行变法，南平百越，北却三晋，楚国国势大振。',100,'战国初期'),('EV052','商鞅变法','先秦','咸阳（今陕西）','卫鞅携带李悝《法经》入秦，辅佐秦孝公推行变法，废井田、开阡陌、奖励军功、推行县制。',100,'战国中期'),('EV053','围魏救赵','先秦','桂陵（今河南长垣）','孙膑率齐军不直接救赵，而围攻魏都大梁，庞涓回师，在桂陵中伏被擒，留下经典战例。',100,'战国中期'),('EV054','马陵之战','先秦','马陵（今山东）','孙膑用减灶计诱庞涓深入，在马陵道设伏，万弩齐发，庞涓兵败自刎，齐军大破魏军。',80,'战国中期'),('EV055','合纵连横','先秦','六国','苏秦以合纵之术游说六国，身佩六国相印；张仪以连横之策破合纵，游说各国亲秦。',100,'战国中期'),('EV056','张仪欺楚','先秦','楚国','张仪以商於六百里地诱骗楚怀王与齐国断交，楚怀王贪利上当，最终客死秦国，留下千古笑柄。',50,'战国中期'),('EV057','胡服骑射','先秦','邯郸（今河北）','赵武灵王推行胡服骑射改革，摒弃中原宽袍大袖，赵国军事实力大增，灭中山国，辟地千里。',100,'战国中期'),('EV058','屈原沉江','先秦','汨罗江（今湖南）','屈原为楚国大夫，因谗言被放逐，忧国忧民，作《离骚》《天问》。楚都被秦攻破后，悲愤投汨罗江而死。',100,'战国末期'),('EV059','蔺相如完璧归赵','先秦','渑池（今河南）','蔺相如奉命出使，以大智大勇于渑池会上斥秦王无礼，完璧归赵，留下"价值连城"典故。',100,'战国末期'),('EV060','将相和','先秦','邯郸（今河北）','蔺相如以"先国家之急"对老将廉颇处处忍让，终使廉颇感悟，亲自负荆请罪，留下将相和千古佳话。',100,'战国末期'),('EV061','长平之战','先秦','长平（今山西高平）','秦将白起大败赵括于长平，坑杀赵军四十万降卒，赵国元气大伤，秦国统一六国的进程大大加快。',80,'战国末期'),('EV062','白起坑卒','先秦','长平（今山西）','长平之战后，白起坑杀四十万赵军降卒，仅放回二百四十名年幼者，天下震惊。',80,'战国末期'),('EV063','信陵君窃符','先秦','大梁（今河南开封）','秦围赵都邯郸，信陵君魏无忌窃取魏王兵符，率军救赵，留下"窃符救赵"之千古义举。',100,'战国末期'),('EV064','秦王灭周','先秦','洛阳（今河南）','秦昭王派将军攻西周，西周文公投降，献出三十六城，周赧王被废为庶人，周朝八百余年统治至此终结。',80,'战国末期'),('EV065','嬴政亲政','秦汉','咸阳（今陕西）','秦王嬴政铲除嫪毐叛乱，罢免吕不韦，开始真正独掌国政，此后三十年东出扫灭六国，建立第一个大一统帝国。',80,'秦王亲政时期'),('EV066','秦灭韩','秦汉','新郑（今河南）','公元前230年，秦将内史腾率军攻韩，俘虏韩王安，韩亡。韩国成为六国中第一个被灭亡的国家。',80,'秦灭六国'),('EV067','秦灭赵','秦汉','邯郸（今河北）','秦将王翦、杨端和分两路攻赵，公元前228年破邯郸，俘虏赵王迁，赵国亡。',80,'秦灭六国'),('EV068','荆轲刺秦','秦汉','咸阳（今陕西）','燕太子丹以荆轲为刺客，携督亢地图与樊於期人头入秦行刺。荆轲刺秦不中，被秦王侍卫斩杀，事败后秦大怒伐燕。',100,'战国末期'),('EV069','秦灭燕','秦汉','蓟城（今北京）','秦将王翦大破燕军于易水河畔，燕王喜杀太子丹求和不成，秦将李信追至辽东，俘燕王喜，燕亡。',80,'秦灭六国'),('EV070','秦灭魏','秦汉','大梁（今河南开封）','公元前225年，秦将王贲引黄河水灌大梁城三月，城破，魏王假投降，魏亡。',80,'秦灭六国'),('EV071','王翦灭楚','秦汉','寿春（今安徽）','秦将王翦率六十万大军伐楚，坚壁不战，养精蓄锐，待楚军松懈后发起进攻，俘虏楚王负刍，楚亡。',100,'秦灭六国'),('EV072','秦灭齐','秦汉','临淄（今山东）','公元前221年，秦将王贲率军从燕国南部攻齐，兵不血刃直入临淄，齐王建不战而降，六国统一，秦始皇建立秦帝国。',80,'秦灭六国'),('EV073','统一度量衡','秦汉','咸阳（今陕西）','秦始皇统一六国后，下令统一度量衡、货币、文字（小篆），建立郡县制，开创两千年中央集权政治制度的基础。',100,'秦朝初期'),('EV074','修筑万里长城','秦汉','北方边疆','秦始皇下令将秦、赵、燕原有长城连接并延伸，西起临洮，东至辽东，绵延万里，成为人类历史上最宏伟的防御工程。',100,'秦朝初期'),('EV075','秦始皇焚书','秦汉','咸阳（今陕西）','公元前213年，秦始皇采纳李斯建议，下令焚烧《诗》《书》及诸子百家典籍，"焚书"钳制了思想自由。',50,'秦朝中期'),('EV076','秦始皇坑儒','秦汉','咸阳（今陕西）','秦始皇因方士卢生、侯生讥讽皇帝而大怒，将四百六十余名儒生活埋于咸阳城外，史称"坑儒"。',50,'秦朝中期'),('EV077','徐福东渡','秦汉','琅琊（今山东）','秦始皇为求长生不老药，命方士徐福率三千童男童女出海东渡寻仙，徐福一去不返。',100,'秦朝中期'),('EV078','蒙恬北击匈奴','秦汉','河套地区','秦将蒙恬率三十万大军北击匈奴，收复河套地区，修筑直道，使匈奴不敢南渡牧马。',50,'秦朝初期'),('EV079','修筑直道','秦汉','北方边疆','蒙恬修筑从咸阳至九原的直道，全长千余里，路基宽阔笔直，是世界上最早的高速公路之一。',50,'秦朝初期'),('EV080','秦始皇驾崩','秦汉','沙丘（今河北）','公元前210年，秦始皇东巡途中病逝于沙丘平台。赵高与李斯合谋篡改遗诏，赐死扶苏，立胡亥为帝。',100,'秦朝中期'),('EV081','指鹿为马','秦汉','咸阳（今陕西）','赵高为试探群臣态度，献给秦二世一匹鹿，说是马。群臣有人直言是鹿，赵高将直言者尽皆治罪。',100,'秦朝末期'),('EV082','大泽乡起义','秦汉','大泽乡（今安徽）','陈胜、吴广因雨误期，按秦法当斩，遂率九百戍卒揭竿而起，喊出"王侯将相宁有种乎"的口号。',100,'秦朝末期'),('EV083','陈胜建张楚','秦汉','陈县（今河南）','陈胜吴广在大泽乡起义后，率军攻占陈县，陈胜被推举为王，建国号"张楚"，各地纷纷响应。',50,'秦朝末期'),('EV084','项梁项羽起兵','秦汉','吴县（今江苏苏州）','项梁项羽叔侄在会稽起兵，率八千江东子弟渡江而西，成为反秦主力，项羽勇冠三军。',100,'秦末汉初'),('EV085','刘邦沛县起兵','秦汉','沛县（今江苏）','泗水亭长刘邦押送戍卒赴骊山，途中戍卒逃亡，刘邦放走剩余戍卒，率十余人在沛县起兵响应陈胜。',100,'秦末汉初'),('EV086','巨鹿·破釜沉舟','秦汉','巨鹿（今河北）','项羽率楚军救赵，在巨鹿以破釜沉舟之决心，九战绝甬道，大败秦将章邯、王离，坑杀秦军二十万。',100,'秦末汉初'),('EV087','章邯降项羽','秦汉','殷墟（今河南）','秦将章邯在巨鹿战败后，率二十万秦军投降项羽，项羽于新安城南坑杀降卒，秦朝军事支柱彻底瓦解。',80,'秦末汉初'),('EV088','刘邦入关中','秦汉','咸阳（今陕西）','刘邦趁项羽在巨鹿与秦军主力决战之际，率军绕过函谷关，攻入咸阳，秦王子婴投降，秦朝正式灭亡。',100,'秦末汉初'),('EV089','鸿门宴','秦汉','鸿门（今陕西西安）','项羽在鸿门设宴欲杀刘邦，项伯为刘邦说情，樊哙闯帐护卫，刘邦借口如厕逃回灞上，留下千古悬案。',100,'楚汉争霸'),('EV090','项羽分封','秦汉','咸阳（今陕西）','项羽灭秦后，自立为西楚霸王，分封十八路诸侯王，刘邦被封为汉王，埋下楚汉战争的导火索。',80,'楚汉争霸'),('EV091','韩信拜将','秦汉','南郑（今陕西汉中）','韩信初投项羽不被用，后归刘邦，经萧何月下追回，刘邦拜韩信为大将军，韩信献"东归争天下"之策。',100,'楚汉争霸'),('EV092','暗度陈仓','秦汉','关中与汉中','刘邦赴汉中后，烧毁栈道以迷惑项羽。韩信派兵佯修栈道，暗中从故道迂回攻入关中。',100,'楚汉争霸'),('EV093','彭城之战','秦汉','彭城（今江苏徐州）','刘邦率五路诸侯共五十六万联军攻占彭城。项羽率三万精骑回师，在彭城西大败刘邦，斩杀十余万汉军。',80,'楚汉争霸'),('EV094','韩信灭魏','秦汉','魏国（今山西）','韩信率军攻魏，用木罂渡河，从夏阳以木盆渡军，俘虏魏王豹，平定魏地，解除刘邦侧翼威胁。',50,'楚汉争霸'),('EV095','韩信灭齐','秦汉','齐国（今山东）','韩信率军伐齐，齐王田广以为郦食其已说降汉军，不设防备，被韩信突袭，齐国覆灭。',80,'楚汉争霸'),('EV096','龙且丧师','秦汉','潍水（今山东）','项羽遣楚将龙且率二十万大军救齐，韩信在潍水列阵，趁龙且渡河时决壅放水，大破楚军，龙且战死。',80,'楚汉争霸'),('EV097','鸿沟为界','秦汉','鸿沟（今河南）','楚汉长期对峙后，双方约定以鸿沟为界，中分天下：西属汉，东属楚。项羽放回刘邦之父妻子，归兵东归。',50,'楚汉争霸'),('EV098','垓下之围','秦汉','垓下（今安徽灵璧）','刘邦毁约，追击东归的项羽，在垴下将项羽重重包围，张良命汉军夜唱楚歌，项羽以为楚地尽失，军心瓦解。',100,'楚汉争霸'),('EV099','霸王别姬','秦汉','垓下（今安徽灵璧）','项羽被困垓下，夜饮帐中，悲歌"力拔山兮气盖世，时不利兮骓不逝"，虞姬起舞相和，拔剑自刎。',100,'楚汉争霸'),('EV100','乌江自刎','秦汉','乌江（今安徽和县）','项羽率残部突围至乌江，乌江亭长以船相迎，项羽以"无颜见江东父老"拒绝，将乌骓赠亭长，持剑自刎而死。',100,'楚汉争霸');

-- Batch 3: EV101 ~ EV123
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV101','汉朝建立','秦汉','洛阳（今河南）','公元前202年，刘邦即皇帝位，定都长安，建立汉朝，史称西汉。中国历史翻开了新的一页。',100,'西汉初期'),('EV102','白登之围','秦汉','平城（今山西）','刘邦亲征匈奴，被冒顿单于率四十万精骑围困于白登山七天七夜，陈平献计以重金贿赂单于阙氏，始得脱围。',100,'西汉初期'),('EV103','韩信之死','秦汉','长安（今陕西西安）','韩信功高震主，先被贬为淮阴侯，后被吕后与陈平骗入长乐宫，以竹剑刺死，一代兵仙就此陨落。',100,'西汉初期'),('EV104','诸吕之乱','秦汉','长安（今陕西西安）','吕后死后，侄子吕禄、吕产专权，妄图篡夺刘氏天下。太尉周勃与陈平设计铲除诸吕，迎立代王刘恒为帝。',80,'西汉初期'),('EV105','文景之治','秦汉','长安（今陕西西安）','汉文帝、汉景帝在位期间，推行轻徭薄赋、与民休息的政策，国力大增，开创封建社会首个治世。',100,'西汉前期'),('EV106','缇萦救父','秦汉','长安（今陕西西安）','齐国太仓令淳于意之女缇萦，父亲含冤将被处刑，缇萦上书汉文帝，愿以身代父受刑。文帝感悟，下令废除肉刑。',50,'西汉初期'),('EV107','七国之乱','秦汉','长安（今陕西西安）','汉景帝时，吴王刘濞联合六国宗室以"清君侧"为名起兵叛乱，周亚夫率军平叛，仅三月即平定。',80,'西汉前期'),('EV108','汉武登基','秦汉','长安（今陕西西安）','十六岁的刘彻即位，是为汉武帝。他雄才大略，开疆拓土，罢黜百家，独尊儒术，开创汉武盛世。',80,'西汉鼎盛期'),('EV109','董仲舒献策','秦汉','长安（今陕西西安）','儒生董仲舒向汉武帝上"天人三策"，建议罢黜百家、独尊儒术，建立太学选拔人才，儒家思想从此成为中国正统。',100,'西汉鼎盛期'),('EV110','推恩令','秦汉','长安（今陕西西安）','主父偃向汉武帝建议，命令诸侯王将封地分给所有子弟，削弱诸侯国势力，"推恩令"是历史上最高明的削藩之策。',100,'西汉鼎盛期'),('EV111','张骞出塞','秦汉','长安（今陕西西安）','汉武帝派张骞出使西域，欲联合月氏夹击匈奴。张骞在匈奴被囚十年，开辟了丝绸之路。',100,'西汉鼎盛期'),('EV112','卫青击匈奴','秦汉','河套地区','汉武帝时，大将军卫青率军北击匈奴，收复河套地区，置朔方郡，是汉朝对匈奴的首次大胜。',80,'西汉鼎盛期'),('EV113','霍去病征匈奴','秦汉','祁连山（今甘肃）','霍去病少年英雄，十八岁首次出征便率八百骑深入敌境，斩获两千余人。此后六次出击匈奴，皆获大胜。',100,'西汉鼎盛期'),('EV114','漠北之战','秦汉','漠北（今蒙古）','卫青、霍去病各率五万骑，分两路深入漠北打击匈奴单于主力，歼灭匈奴主力九万余人，匈奴从此远遁。',80,'西汉鼎盛期'),('EV115','封狼居胥','秦汉','狼居胥山（今蒙古）','霍去病率军北击匈奴，深入漠北，登狼居胥山筑坛祭天，成为中国武将最高荣誉的代称。',100,'西汉鼎盛期'),('EV116','丝绸之路','秦汉','西域（今新疆及中亚）','张骞凿空西域后，汉朝与西域及中亚各国建立联系，丝绸、瓷器、茶叶等商品源源西运，东西方文明开始大规模交流。',100,'西汉鼎盛期'),('EV117','苏武牧羊','秦汉','北海（今贝加尔湖）','汉使苏武出使匈奴被扣，坚贞不屈，在北海边牧羊十九年，须发尽白，归汉后被封为典属国，留下千古忠节佳话。',100,'西汉中期'),('EV118','巫蛊之祸','秦汉','长安（今陕西西安）','汉武帝晚年，奸臣江充诬陷太子刘据行巫蛊诅咒皇帝，太子被迫起兵，兵败后自杀，株连数万人，是汉朝最大的宫廷惨案。',80,'西汉末期'),('EV119','霍光辅政','秦汉','长安（今陕西西安）','汉武帝临终托孤于霍光，霍光辅佐昭帝、宣帝，废昏立明，权倾朝野，是历史上权臣的典型代表。',50,'西汉中期'),('EV120','昭宣中兴','秦汉','长安（今陕西西安）','汉昭帝、汉宣帝在位期间，霍光等辅政，轻徭薄赋，整顿吏治，西汉国力再度恢复，史称"昭宣中兴"。',50,'西汉中期'),('EV121','设西域都护府','秦汉','乌垒（今新疆轮台）','汉宣帝命郑吉为西域都护，设立西域都护府于乌垒，统领天山南北诸国，西域正式纳入汉朝版图。',80,'西汉中期'),('EV122','昭君出塞','秦汉','长安（今陕西西安）','汉元帝时，宫女王昭君自愿请行远嫁匈奴呼韩邪单于，为汉匈带来数十年和平，留下千古和亲佳话。',100,'西汉末期'),('EV123','王莽篡汉','秦汉','长安（今陕西西安）','王莽以外戚身份辅政渐掌大权，公元9年废孺子婴自立为帝，建立新朝，西汉覆亡，王莽推行新政改革。',80,'新朝');

